import android.content.Intent
import android.net.Uri
import androidx.appcompat.app.AppCompatActivity
import android.os.Bundle
import android.widget.Toast

class MainActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_main)

        handleDeepLink(intent)
    }

    override fun onNewIntent(intent: Intent) {
        super.onNewIntent(intent)
        handleDeepLink(intent)
    }

    private fun handleDeepLink(intent: Intent) {
        if (intent.action == Intent.ACTION_VIEW && intent.data != null) {
            val uri = intent.data
            when (uri.host) {
                "profile" -> handleProfile(uri)
                "payment" -> handlePayment(uri)
                else -> Toast.makeText(this, "Invalid deep link", Toast.LENGTH_SHORT).show()
            }
        }
    }

    private fun handleProfile(uri: Uri) {
        val userId = uri.pathSegments.getOrNull(1)
        if (userId != null && isValidUserId(userId)) {
            // Navigate to ProfileActivity with user ID
            startActivity(Intent(this, ProfileActivity::class.java).putExtra("user_id", userId))
        } else {
            Toast.makeText(this, "Invalid user ID", Toast.LENGTH_SHORT).show()
        }
    }

    private fun handlePayment(uri: Uri) {
        val action = uri.pathSegments.getOrNull(1)
        if (action != null && isValidAction(action)) {
            // Navigate to PaymentActivity with action
            startActivity(Intent(this, PaymentActivity::class.java).putExtra("action", action))
        } else {
            Toast.makeText(this, "Invalid payment action", Toast.LENGTH_SHORT).show()
        }
    }

    private fun isValidUserId(userId: String): Boolean {
        // Add validation logic for user ID
        return userId.matches(Regex("\\d+"))
    }

    private fun isValidAction(action: String): Boolean {
        // Add validation logic for payment actions
        return when (action) {
            "confirm" -> true
            else -> false
        }
    }
}